import{_ as t,c as r,o as e,d as o}from"./app.0d10a45e.js";var n="/assets/orange-square.13c7a07e.png",s="/images/build/zdaniya-06.png";const B='{"title":"\u041C\u0430\u043D\u0438\u0444\u0435\u0441\u0442","description":"","frontmatter":{"title":"\u041C\u0430\u043D\u0438\u0444\u0435\u0441\u0442","subtitle":"\u041E\u0441\u043D\u043E\u0432\u043E\u043F\u043E\u043B\u0430\u0433\u0430\u044E\u0449\u0438\u0435 \u0438\u0434\u0435\u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0430","date":"2014-10-21","cover":"Heading.png"},"headers":[],"relativePath":"theory/system/manifest/index.md"}',p={},a=o('<p><strong><a href="http://OOLEY.ru" class="external-link" target="_blank" rel="noopener noreferrer">OOLEY.ru</a></strong>\xA0\u2014 \u044D\u0442\u043E \u0441\u0435\u0442\u044C \u043F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u0438 \u0438 \u0441\u0440\u0435\u0434\u0430 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <strong>\u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u0438 \u0443\u043C\u0435\u043D\u0438\u0439**</strong>, ** \u0430 \u0442\u0430\u043A\u0436\u0435 \u0446\u0435\u043D\u0442\u0440 \u0438\u0437\u0443\u0447\u0435\u043D\u0438\u044F \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438, \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u043C\u043E\u0434\u0435\u043B\u0435\u0439 \u0438 \u043F\u043E\u043B\u043D\u043E\u043C\u0430\u0441\u0448\u0442\u0430\u0431\u043D\u043E\u0439 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0445 **\u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u0445 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445.**</p><p>\u0412 \u043A\u043E\u043D\u0446\u0435 \u0432\u0435\u043A\u0430 \u0432\u0441\u0435\u043E\u0431\u0449\u0435\u0439 \u0432\u0435\u0440\u044B \u0432 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0435 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u0440\u044B\u043D\u043A\u0430, \u0432 \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u043E\u0433\u043E, \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E \u044F\u0440\u043A\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F \u0444\u043E\u043A\u0443\u0441\u0438\u0440\u043E\u0432\u043A\u0438 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u043D\u0430 \u0443\u0437\u043A\u043E\u0439 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438, \xA0\u0432\u044B\u0441\u043E\u043A\u043E\u0439 \u043A\u043E\u043D\u043A\u0443\u0440\u0435\u043D\u0446\u0438\u0438 \u0438 \u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E\u043C \u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u0438\u0438 \u043A\u0430\u043A \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u0430\u0445 \u0438 \u0438\u0434\u0435\u0430\u043B\u0430\u0445 \u0434\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0438\u0437 \u0435\u0433\u043E \u0447\u043B\u0435\u043D\u043E\u0432. \u041F\u043E\u0438\u0441\u043A \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0432\u0435\u0441\u043E\u0432 \u0434\u043B\u044F \u044D\u0442\u0438\u0445 \u043D\u0430\u0440\u0443\u0448\u0435\u043D\u0438\u0439 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0440\u0430\u0432\u043D\u043E\u0432\u0435\u0441\u0438\u044F \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u043A \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u043E\u0439 \u0441\u0440\u0435\u0434\u044B \u0438 \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0439 \u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u044B \u0434\u043B\u044F \u0448\u0438\u0440\u043E\u043A\u043E\u0433\u043E \u043E\u0431\u043C\u0435\u043D\u0430 \u0438 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u0438 \u0443\u043C\u0435\u043D\u0438\u0439, \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0443\u0441\u043B\u043E\u0432\u0438\u0439 \u0434\u043B\u044F \u0432\u0437\u0430\u0438\u043C\u043E\u0432\u044B\u0433\u043E\u0434\u043D\u043E\u0439 \u043A\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0441\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0439 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0434\u043B\u044F \u043C\u0430\u043A\u0441\u0438\u043C\u0430\u043B\u044C\u043D\u043E \u0448\u0438\u0440\u043E\u043A\u043E\u0433\u043E \u043A\u0440\u0443\u0433\u0430 \u043B\u0438\u0446.</p><blockquote><p><strong>\u041D\u0430\u0432\u044B\u043A</strong> \u2014 \u0434\u043E\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0435 \u0434\u043E \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0437\u043C\u0430\xA0\u0443\u043C\u0435\u043D\u0438\u0435 \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0438\u043B\u0438 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B \u0441 \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u0435\u043C \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430 \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0440\u0443\u043A\u043E\u0432\u043E\u0434\u0441\u0442\u0432\u043E \u043F\u043E \u043E\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u044E \u0438\u043C.</p></blockquote><p>\u0414\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E, \u043A\u0442\u043E \u0434\u043E\u043B\u0433\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0443\u0437\u043A\u043E \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E, \u043E\u0447\u0435\u043D\u044C \u0432\u0430\u0436\u043D\u043E \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438\xA0\u043E\u0441\u0432\u0430\u0438\u0432\u0430\u0442\u044C\xA0\u043D\u043E\u0432\u044B\u0435\xA0\u043D\u0430\u0432\u044B\u043A\u0438 \u0438 \u0443\u043C\u0435\u043D\u0438\u044F \u0434\u043B\u044F \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0441\u0432\u043E\u0435\u0439 \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0433\u043E \u0440\u0430\u0431\u043E\u0442\u043E\u0434\u0430\u0442\u0435\u043B\u044F \u0438\u043B\u0438 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438. \u0423\u0432\u0435\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B\u0430\u0445 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0441 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0439. \u041D\u043E \u0432 \u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0435\u0441\u043B\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0443\u0432\u0435\u0440\u0435\u043D \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0445 \u0440\u0430\u043C\u043A\u0430\u0445 \u0441\u0432\u043E\u0435\u0439 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u043D\u0435\u0440\u0435\u0434\u043A\u043E \u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u0440\u0430\u0441\u0442\u0435\u0440\u044F\u043D\u043D\u043E\u0441\u0442\u0438, \u0441\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u044F\u0441\u044C \u0441 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044F\u043C\u0438, \u0442\u0440\u0435\u0431\u0443\u044E\u0449\u0438\u0445 \u0431\u043E\u043B\u0435\u0435 \u0448\u0438\u0440\u043E\u043A\u043E\u0433\u043E \u043A\u0440\u0443\u0433\u0430 \u043A\u0430\u043A \u0442\u0435\u043E\u0440\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E, \u0442\u0430\u043A \u0438 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430, \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u0430 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u044C \u0432\xA0\u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0438 \u043A\u0440\u0443\u0433\u043E\u0437\u043E\u0440\u0430 \u0438 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u0438 \u0438 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043D\u043E\u0432\u044B\u0445 \u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u0438 \u0443\u043C\u0435\u043D\u0438\u0439 \u0432 \u0438\u043D\u044B\u0445 \u0441\u0444\u0435\u0440\u0430\u0445 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438.</p><p><strong>OOLEY</strong> \u0441\u0442\u0440\u0435\u043C\u0438\u0442\u0441\u044F \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0442\u044C \u043C\u0430\u043A\u0441\u0438\u043C\u0430\u043B\u044C\u043D\u043E \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u0443\u044E \u0441\u0440\u0435\u0434\u0443 \u0434\u043B\u044F \u0432\u044B\u0440\u0430\u0431\u043E\u0442\u043A\u0438, \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u0448\u0438\u0440\u043E\u043A\u043E\u0433\u043E \u0441\u043F\u0435\u043A\u0442\u0440\u0430 \u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u0438 \u0443\u043C\u0435\u043D\u0438\u0439. \u041F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044F \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0434\u043B\u044F \u043F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u0438, \u043E\u0431\u043C\u0435\u043D\u0430 \u0438 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043D\u0430\u0432\u044B\u043A\u043E\u0432, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445 \u0438 \u0438\u0445 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u0445, \u0443\u043C\u0435\u043B\u044C\u0446\u0430\u0445 \u0438 \u0443\u043C\u0435\u043B\u0438\u0446\u0430\u0445, \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u0445 \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u0445, \u0441\u043E\u0431\u044B\u0442\u0438\u044F\u0445, \u043F\u0440\u043E\u0435\u043A\u0442\u0430\u0445 \u0438 \u0438\u0445\xA0\u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u0445, OOLEY \u0441\u043F\u043E\u0441\u043E\u0431\u0441\u0442\u0432\u0443\u0435\u0442 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044E \u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044E \u043E\u0441\u043E\u0431\u043E\u0439\xA0\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0439\xA0\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u043E\u0439 \u0441\u0440\u0435\u0434\u044B \u0432 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435.</p><blockquote><p><strong>\u0423\u043C\u0435\u043D\u0438\u0435</strong> \u2014 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u043E \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u0435\u043C\u0430\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0443\u044E \u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0430\u0446\u0438\u044E \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u044B\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u044E\u0449\u0438\u043C\u0438 \u043D\u0430\u0434\u0435\u0436\u043D\u043E \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u0434\u0430\u0436\u0435 \u0432 \u043C\u0435\u043D\u044F\u044E\u0449\u0438\u0445\u0441\u044F \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445.</p></blockquote><p>\u0423\u043C\u0435\u043D\u0438\u044F \u0441\u043E\u0447\u0435\u0442\u0430\u044E\u0442 \xA0\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u0443\u044E \xA0\u0446\u0435\u043B\u0435\u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u0443\u044E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \xA0\u0438 \xA0\u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0430\u0446\u0438\u044E\xA0\u0438\u043C\u0435\u044E\u0449\u0438\u0445\u0441\u044F \u043D\u0430\u0432\u044B\u043A\u043E\u0432, \u0438\u043C\u0435\u043D\u043D\u043E \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0441 \u0440\u043E\u0441\u0442\u043E\u043C \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043D\u0430\u0432\u044B\u043A\u043E\u0432, \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u043E \u0443\u043C\u0435\u043D\u0438\u0439 \u043C\u043E\u0436\u0435\u0442 \u0440\u0430\u0441\u0442\u0438 \u043F\u0440\u043E\u043F\u043E\u0440\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\xA0\u0440\u043E\u0441\u0442\u0443 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u043A\u043E\u043C\u0431\u0438\u043D\u0430\u0446\u0438\u0439 \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432.</p><p>\u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u043E\u0433\u0440\u043E\u043C\u043D\u044B\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u043A\u043E\u043C\u043F\u044C\u044E\u0442\u0435\u0440\u043D\u044B\u0445 \u0441\u0435\u0442\u0435\u0439 \u043F\u043E \u043E\u0431\u043C\u0435\u043D\u0443 \u0437\u043D\u0430\u043D\u0438\u044F\u043C\u0438, \u0434\u0430\u043B\u0435\u043A\u043E \u043D\u0435 \u0432\u0441\u0435 \u0437\u043D\u0430\u043D\u0438\u044F \u043C\u043E\u0436\u043D\u043E \u043F\u043E\u0441\u0442\u0438\u0447\u044C \u0442\u043E\u043B\u044C\u043A\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044F\xA0\u0438\u0445\xA0\u0447\u0435\u0440\u0435\u0437 \u044D\u043A\u0440\u0430\u043D. \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0435 \xA0\u0438 \u043C\u043E\u0434\u0435\u043B\u0438 \u0438\u0445 \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0442\u044C \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 \u0438\xA0\u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0441\u0442\u0438 \u0434\u043B\u044F \u0448\u0438\u0440\u043E\u043A\u043E\u0433\u043E \u043E\u0431\u043C\u0435\u043D\u0430 \u043D\u0430\u0432\u044B\u043A\u0430\u043C\u0438, \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438, \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u043C\u0438 \u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438 \u0442\u0440\u0443\u0434\u0430.</p><p><img src="'+n+'" alt=""></p><p>\u0418\u043C\u0435\u043D\u043D\u043E \u043F\u043E\u044D\u0442\u043E\u043C\u0443 <strong>OOLEY</strong> \u0441\u0442\u0430\u0432\u0438\u0442 \u0441\u0435\u0431\u0435 \u0437\u0430\u0434\u0430\u0447\u0443 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0438 \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043C\u043E\u0434\u0435\u043B\u0435\u0439 \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u043B\u043D\u043E\u043C\u0430\u0441\u0448\u0442\u0430\u0431\u043D\u043E\u0439 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0445 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u0445 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445.</p><p>\u041D\u0430\u0432\u044B\u043A\u0438 \u0438 \u0443\u043C\u0435\u043D\u0438\u044F \u043F\u043E-\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C\u0443 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043F\u0440\u0438 \u043D\u0430\u043B\u0438\u0447\u0438\u0438 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0433\u043E \u0438 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E\u0433\u043E \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430 \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043F\u0440\u0438 \u043D\u0430\u043B\u0438\u0447\u0438\u0438 \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0435\u0439 \u043A\u043E\u043C\u043F\u0430\u043D\u0438\u0438 \u0443\u043C\u0435\u043B\u044C\u0446\u0435\u0432 \u0438 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043F\u043E\u043B\u0435\u0437\u043D\u044B\u0445 \u043F\u043B\u043E\u0449\u0430\u0434\u0435\u0439. \u041C\u0430\u043A\u0441\u0438\u043C\u0430\u043B\u044C\u043D\u0430\u044F \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438 \u0433\u0438\u0431\u043A\u043E\u0441\u0442\u044C \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439\xA0\u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B \u0434\u043B\u044F \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u044F \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0445 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0435\u0439 \u0438\xA0\u0434\u043B\u044F \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0442\u0440\u0430\u043D\u0441\u0434\u0438\u0441\u0446\u0438\u043F\u043B\u0438\u043D\u0430\u0440\u043D\u044B\u0445<a href="https://ru.wikipedia.org/wiki/%D0%A2%D1%80%D0%B0%D0%BD%D1%81%D0%B4%D0%B8%D1%81%D1%86%D0%B8%D0%BF%D0%BB%D0%B8%D0%BD%D0%B0%D1%80%D0%BD%D0%BE%D1%81%D1%82%D1%8C" class="external-link" target="_blank" rel="noopener noreferrer">*</a>\xA0\u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0432.</p><p>\u0422\u0430\u043A\u0436\u0435 \u043A\u0430\u043A \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442 \u0431\u0435\u0441\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0435 \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u044B \u0443\u043C\u0435\u043D\u0438\u0439, \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u043B\u044E\u0434\u0435\u0439, \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0438\u0445 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u043D\u0430\u0432\u044B\u043A\u0430\u043C\u0438 \u0438 \u0443\u043C\u0435\u043D\u0438\u044F\u043C\u0438 \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442 \u0431\u0435\u0441\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0435 \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u044B \u043A\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0432\u0441\u0435 \u0431\u043E\u043B\u0435\u0435 \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u0438 \u043C\u0430\u0441\u0448\u0442\u0430\u0431\u043D\u044B\u0445 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432. \u0421\u043E\u0437\u0434\u0430\u0432\u0430\u044F \u0443\u0441\u043B\u043E\u0432\u0438\u044F \u0434\u043B\u044F \u0441\u043D\u0438\u0436\u0435\u043D\u0438\u044F \u043A\u043E\u043D\u043A\u0443\u0440\u0435\u043D\u0446\u0438\u0438 \u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0441\u0442\u0432\u0443\u044F \u043A\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 \u043C\u0435\u0436\u0434\u0443 \u043B\u044E\u0434\u044C\u043C\u0438, \u043A\u043E\u043C\u043F\u0430\u043D\u0438\u044F\u043C\u0438 \u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430\u043C\u0438, <strong>OOLEY</strong> \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u0442\xA0\u0432\u0441\u0435 \u0431\u043E\u043B\u0435\u0435 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u0435 \u0444\u043E\u0440\u043C\u044B \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u043C\u0435\u0436\u0434\u0443 \u043D\u0438\u043C\u0438.</p><p>\u041E\u0442\u043A\u0440\u044B\u0442\u043E\u0441\u0442\u044C \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0434\u043E\u0441\u0442\u0443\u043F\u0430 \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0448\u0438\u0440\u043E\u043A\u043E\u0433\u043E \u043A\u0440\u0443\u0433\u0430 \u0437\u0430\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u043B\u0438\u0446, \u0441 \u0443\u0447\u0435\u0442\u043E\u043C \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u043B\u0438\u0446\u0430\u043C\u0438 \u0431\u0435\u0437 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043D\u0430\u0432\u044B\u043A\u043E\u0432, \u043D\u043E \u0441 \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0438\u0445 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0438\u043B\u0438 \u0434\u043E\u043A\u0430\u0437\u0430\u0442\u044C.</p><p>\u0423\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0443\u0435\u043C\u043E\u0441\u0442\u044C \u0438 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C \u043C\u043E\u0434\u0435\u043B\u0438 \u0435\u0451 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F, \u0444\u0438\u043D\u0430\u043D\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u043C\u0438, \u0440\u0430\u0441\u043F\u043E\u0440\u044F\u0436\u0435\u043D\u0438\u044F \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438, \u0432\u044B\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0438 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0443\u043C\u0435\u043D\u0438\u0439 \u0438 \u043D\u0430\u0432\u044B\u043A\u043E\u0432, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0433\u0438\u0431\u043A\u043E\u0441\u0442\u044C \u0432\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0438\xA0\u0441 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u0442\u0435\u0440\u0440\u0438\u0442\u043E\u0440\u0438\u044F\u043C\u0438, \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u0430\u043C\u0438, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u043C\u0438 \u043D\u0430\u0441\u0435\u043B\u0435\u043D\u0438\u044F \u0438 \u0442\u0435\u043C\u043F\u0430\u043C\u0438 \u044D\u0432\u043E\u043B\u044E\u0446\u0438\u0438 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0438.</p><p>\u0412 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u044F\u0441\u043D\u043E \u043D\u0430\u043C\u0435\u0442\u0438\u0432\u0448\u0435\u0433\u043E\u0441\u044F &quot;\u043A\u0440\u0438\u0437\u0438\u0441\u0430 \u043F\u0435\u0440\u0435\u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0430&quot;, \u043A\u043E\u0433\u0434\u0430 \u0441\u043F\u0440\u043E\u0441 \u043D\u0430 \u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u0438\u0435 \u0442\u043E\u0432\u0430\u0440\u043E\u0432 \u0438 \u0443\u0441\u043B\u0443\u0433 \u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043D\u0430\u0441\u044B\u0449\u0435\u043D\u043D\u044B\u043C \u0438 \u0441\u0442\u0440\u0435\u043C\u0438\u0442\u0441\u044F \u043A \u0441\u043D\u0438\u0436\u0435\u043D\u0438\u044E, \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u043E\u0441\u0442\u0440\u043E \u0432\u0441\u0442\u0430\u0435\u0442 \u0432\u043E\u043F\u0440\u043E\u0441 \u043E \u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u0438 \u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u0438\u044F \u0432\xA0\u0441\u0444\u0435\u0440\u0435 \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0435\u0439 \u0438 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0447\u043B\u0435\u043D\u0430 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430. <strong>OOLEY</strong> \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442 \u043E\u0431\u0440\u0430\u0442\u0438\u0442\u044C \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 \u043C\u0430\u043B\u043E\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u043D\u044B\u0435 \u0438 \u043F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E \u043D\u0435\u0438\u0441\u0447\u0435\u0440\u043F\u0430\u0435\u043C\u044B\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0438 \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430 \u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u043E\u0439 \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438. \u0414\u043E\u0431\u0440\u043E\u0432\u043E\u043B\u044C\u043D\u0430\u044F \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u0430\u044F\xA0\u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u0448\u0438\u0440\u043E\u043A\u043E\u0433\u043E \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u0438 \u0443\u043C\u0435\u043D\u0438\u0439, \u043F\u0440\u043E\u0437\u0440\u0430\u0447\u043D\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0434\u043E\u0441\u0442\u0443\u043F\u0430 \u043A \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u043C, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0433\u043E \u0440\u0430\u0441\u043F\u043E\u0440\u044F\u0436\u0435\u043D\u0438\u044F \u0435\u0451 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438, \u2014 \u043F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E \u043D\u0430\u0434\u0435\u0436\u043D\u043E\u0435 \xA0\u0438 \u0440\u0430\u0431\u043E\u0442\u043E\u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u0440\u043E\u0431\u043B\u0435\u043C, \u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0438\u0445 \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E\u0439 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438 \u043D\u0430 \u0440\u044B\u043D\u043E\u0447\u043D\u043E-\u043A\u0430\u043F\u0438\u0442\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 \u0432\u043E\u0441\u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0430.</p><p><strong>OOLEY</strong> \u2014 \u044D\u0442\u043E \u043D\u0435 \u0433\u043E\u0442\u043E\u0432\u043E\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0435, \u044D\u0442\u043E \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u0430 \u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u043C\u0430\u0441\u0448\u0442\u0430\u0431\u043D\u043E\u0439 \u0434\u0438\u0441\u043A\u0443\u0441\u0441\u0438\u0438, \u043F\u043B\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0439 \u0438 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u043E\u0432 \u0441 \u043F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u0435\u0439 \u0438\u0445 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432, \u043F\u043E\u0438\u0441\u043A\u0430 \u0438 \u043F\u0440\u043E\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0435\u0439 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0444\u043E\u0440\u043C\xA0\u0438 \u043C\u043E\u0434\u0435\u043B\u0435\u0439 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u043B\u043D\u043E\u043C\u0430\u0441\u0448\u0442\u0430\u0431\u043D\u043E\u0439 \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u043E\u0439 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445 \u0438 \u043D\u0430\u043B\u0430\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u0438\u0445 \u0432\u0437\u0430\u0438\u043C\u043E\u0441\u0432\u044F\u0437\u0435\u0439.</p><p><img src="'+s+'" alt=""></p>',17),_=[a];function i(g,c,l,D,d,u){return e(),r("div",null,_)}var m=t(p,[["render",i]]);export{B as __pageData,m as default};
